   765	            return @"SDK not initialized";
   766	        case oaaErrNoSuchUser:
   767	            return @"User not found";
   768	        case oaaErrCannotAddUser:
   769	            return @"Failed to add user";
   770	        case oaaErrNoSuchApp:
   771	            return @"App bundle not found";
   772	        case oaaErrMalformedBundle:
   773	            return @"Invalid app bundle format";
   774	        case oaaErrFileSystemErr:
   775	            return @"Filesystem operation failed";
   776	        case oaaErrMalformedResources:
   777	            return @"Corrupted resource files";
   778	        case oaaErrUnknown:
   779	            return @"Unknown initialization error";
   780	        default:
   781	            return [NSString stringWithFormat:@"Unmapped error: %d", errorCode];
   782	    }
   783	}
